"use client";

import { useEffect, useState, useMemo } from "react";
import { Invoice, PurchaseOrder, Vendor, InvoiceStatus } from "@/types";
import { getInvoices, createInvoice, updateInvoiceStatus } from "@/lib/invoices";
import { getPurchaseOrders } from "@/lib/purchaseOrders";
import { getVendors } from "@/lib/vendors";
import { formatCurrency } from "@/lib/currencies";
import { useModal } from "@/context/ModalContext";
import InvoiceDetailModal from "@/components/invoices/InvoiceDetailModal";

import CustomSelect from "@/components/ui/CustomSelect";
import InvoiceUpload from "@/components/invoices/InvoiceUpload";
import { updateInvoiceStatus as updateStatus } from "@/lib/invoices"; // Avoiding name collision


export default function InvoicesPage() {
    // Data State
    const { showConfirm, showAlert, showError } = useModal();
    const [invoices, setInvoices] = useState<Invoice[]>([]);
    const [pos, setPos] = useState<PurchaseOrder[]>([]);
    const [vendors, setVendors] = useState<Vendor[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);

    // Selection for Detail View
    const [selectedInvoice, setSelectedInvoice] = useState<Invoice | null>(null);

    const [formData, setFormData] = useState({
        poId: "",
        invoiceNumber: "",
        amount: 0,
        currency: "USD",
        issueDate: new Date().toISOString().split('T')[0],
        dueDate: new Date().toISOString().split('T')[0],
        fileName: "",
        fileUrl: ""
    });

    // Filter State
    const [searchQuery, setSearchQuery] = useState("");
    const [statusFilter, setStatusFilter] = useState('ALL');

    // Stats Calculation
    const stats = useMemo(() => {
        const pending = invoices.filter(i => i.status === 'PENDING').reduce((acc, i) => acc + i.amount, 0);
        const overdue = invoices.filter(i => i.status === 'PENDING' && new Date(i.dueDate) < new Date()).length;
        const totalAmount = invoices.reduce((acc, i) => acc + i.amount, 0);
        const matchRate = invoices.length > 0
            ? Math.round((invoices.filter(i => i.status === 'PAID' || i.status === 'APPROVED').length / invoices.length) * 100)
            : 0;

        return { pending, overdue, totalAmount, matchRate };
    }, [invoices]);

    const filteredInvoices = useMemo(() => {
        return invoices.filter(inv => {
            const matchesSearch = inv.invoiceNumber.toLowerCase().includes(searchQuery.toLowerCase()) ||
                inv.vendorName.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesStatus = statusFilter === 'ALL' || inv.status === statusFilter;
            return matchesSearch && matchesStatus;
        });
    }, [invoices, searchQuery, statusFilter]);

    const fetchData = async () => {
        setLoading(true);
        const [invData, poData, vendorData] = await Promise.all([
            getInvoices(),
            getPurchaseOrders(),
            getVendors()
        ]);
        setInvoices(invData.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()));
        setPos(poData);
        setVendors(vendorData);
        setLoading(false);
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            const selectedPO = pos.find(p => p.id === formData.poId);
            // Validations
            if (!selectedPO) {
                await showAlert("Invalid PO", "Please select a valid Purchase Order");
                return;
            }

            // 3-Way Match Check (Simplified for now: Check Amount)
            if (formData.amount > selectedPO.totalAmount) {
                const confirmed = await showConfirm(
                    "3-Way Match Warning",
                    `Invoice amount (${formatCurrency(formData.amount, formData.currency)}) exceeds PO amount (${formatCurrency(selectedPO.totalAmount, selectedPO.currency)}).\n\nDo you want to continue?`
                );
                if (!confirmed) return;
            }

            await createInvoice({
                vendorId: selectedPO.vendorId,
                vendorName: selectedPO.vendorName,
                poId: selectedPO.id,
                poNumber: selectedPO.poNumber,
                invoiceNumber: formData.invoiceNumber,
                amount: formData.amount,
                currency: formData.currency,
                issueDate: new Date(formData.issueDate),
                dueDate: new Date(formData.dueDate),
                status: 'PENDING'
            });

            setShowModal(false);
            setFormData({ poId: "", invoiceNumber: "", amount: 0, currency: "USD", issueDate: new Date().toISOString().split('T')[0], dueDate: new Date().toISOString().split('T')[0] });
            fetchData();
        } catch (error) {
            await showError("Error", "Error creating invoice");
        }
    };

    const handlePay = async (id: string) => {
        const confirmed = await showConfirm("Confirm Payment", "Mark this invoice as PAID?");
        if (!confirmed) return;

        try {
            await updateStatus(id, 'PAID');
            setSelectedInvoice(null);
            fetchData();
        } catch (e) {
            await showError("Error", "Error updating status");
        }
    };

    const handleStatusUpdate = async (id: string, status: InvoiceStatus) => {
        try {
            await updateStatus(id, status);
            setSelectedInvoice(null);
            fetchData();
        } catch (e) {
            await showError("Error", "Error updating status");
        }
    };

    if (loading) return <div>Loading Invoices...</div>;

    return (
        <div style={{ padding: '1rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div>
                    <h1 style={{ fontSize: '1.875rem', fontWeight: 900, color: 'var(--primary)', letterSpacing: '-0.03em', marginBottom: '0.25rem' }}>Finance Operations</h1>
                    <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Manage vendor invoices, 3-way matching, and payment approvals.</p>
                </div>
                <button className="btn btn-primary" onClick={() => setShowModal(true)} style={{ padding: '0.75rem 1.5rem', borderRadius: '12px' }}>+ Record Invoice</button>
            </div>

            {/* Stats Cards */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1.5rem', marginBottom: '2.5rem' }}>
                {[
                    { label: 'Total Volume', value: formatCurrency(stats.totalAmount, 'USD'), icon: '📊', color: 'var(--accent)' },
                    { label: 'Pending Payment', value: formatCurrency(stats.pending, 'USD'), icon: '⏳', color: '#F59E0B' },
                    { label: 'Overdue Invoices', value: stats.overdue, icon: '⚠️', color: '#EF4444' },
                    { label: 'Match Rate', value: `${stats.matchRate}%`, icon: '🎯', color: 'var(--success)' }
                ].map((stat, i) => (
                    <div key={i} className="card" style={{ padding: '1.5rem', display: 'flex', alignItems: 'center', gap: '1rem' }}>
                        <div style={{ fontSize: '2rem', background: `${stat.color}10`, width: '56px', height: '56px', borderRadius: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{stat.icon}</div>
                        <div>
                            <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', fontWeight: 600, textTransform: 'uppercase' }}>{stat.label}</div>
                            <div style={{ fontSize: '1.25rem', fontWeight: 900, color: 'var(--text-main)' }}>{stat.value}</div>
                        </div>
                    </div>
                ))}
            </div>

            {/* Filter Bar */}
            <div className="card" style={{ marginBottom: '1.5rem', padding: '1rem', display: 'flex', gap: '1rem', alignItems: 'center' }}>
                <div style={{ position: 'relative', flex: 1 }}>
                    <span style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', opacity: 0.5 }}>🔍</span>
                    <input
                        type="text"
                        placeholder="Search Invoice # or Vendor..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        style={{ width: '100%', padding: '0.75rem 1rem 0.75rem 2.5rem', borderRadius: '10px', border: '1px solid var(--border)', background: 'var(--background)' }}
                    />
                </div>
                <div style={{ display: 'flex', gap: '0.5rem' }}>
                    {['ALL', 'PENDING', 'APPROVED', 'PAID', 'REJECTED'].map(status => (
                        <button
                            key={status}
                            onClick={() => setStatusFilter(status)}
                            style={{
                                padding: '0.5rem 1rem',
                                borderRadius: '8px',
                                fontSize: '0.8rem',
                                fontWeight: 700,
                                transition: 'all 0.2s',
                                border: '1px solid var(--border)',
                                background: statusFilter === status ? 'var(--primary)' : 'var(--surface)',
                                color: statusFilter === status ? 'white' : 'var(--text-secondary)'
                            }}
                        >
                            {status}
                        </button>
                    ))}
                </div>
            </div>

            {/* Create Invoice Modal */}
            {showModal && (
                <div style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 50 }}>
                    <div className="card" style={{ width: '500px', maxWidth: '90%' }}>
                        <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1rem' }}>Record Vendor Invoice</h2>
                        <form onSubmit={handleSubmit}>
                            <div style={{ marginBottom: '1rem' }}>
                                <CustomSelect
                                    label="Select Purchase Order"
                                    value={formData.poId}
                                    onChange={(val) => {
                                        const selectedPO = pos.find(p => p.id === val);
                                        setFormData({
                                            ...formData,
                                            poId: val,
                                            currency: selectedPO?.currency || 'USD',
                                            // Auto-generate Invoice #
                                            invoiceNumber: selectedPO ? `INV-${selectedPO.poNumber}` : ""
                                        });
                                    }}
                                    options={[
                                        { label: "-- Select PO --", value: "" },
                                        ...pos.filter(p => p.status !== 'CLOSED').map(po => ({
                                            label: `${po.poNumber} — ${po.vendorName} (${formatCurrency(po.totalAmount, po.currency)})`,
                                            value: po.id!
                                        }))
                                    ]}
                                    placeholder="Select PO"
                                />
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem' }}>Invoice #</label>
                                    <input type="text" required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.invoiceNumber} onChange={e => setFormData({ ...formData, invoiceNumber: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem' }}>Amount ({formData.currency})</label>
                                    <input type="number" step="0.01" required style={{ width: '100%', padding: '0.5rem', border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)' }}
                                        value={formData.amount} onChange={e => setFormData({ ...formData, amount: Number(e.target.value) })} />
                                </div>
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', fontWeight: 700 }}>Issue Date</label>
                                    <input type="date" required style={{ width: '100%', padding: '0.75rem', border: '1px solid var(--border)', borderRadius: '10px', background: 'var(--background)' }}
                                        value={formData.issueDate} onChange={e => setFormData({ ...formData, issueDate: e.target.value })} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', fontWeight: 700 }}>Due Date</label>
                                    <input type="date" required style={{ width: '100%', padding: '0.75rem', border: '1px solid var(--border)', borderRadius: '10px', background: 'var(--background)' }}
                                        value={formData.dueDate} onChange={e => setFormData({ ...formData, dueDate: e.target.value })} />
                                </div>
                            </div>

                            <div style={{ marginBottom: '1.5rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', fontWeight: 700 }}>Invoice Attachment</label>
                                <InvoiceUpload
                                    onFileSelect={(file) => {
                                        if (file) {
                                            setFormData({ ...formData, fileName: file.name, fileUrl: 'mock-url' });
                                        } else {
                                            setFormData({ ...formData, fileName: "", fileUrl: "" });
                                        }
                                    }}
                                />
                            </div>

                            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end', borderTop: '1px solid var(--border)', paddingTop: '1.5rem' }}>
                                <button type="button" className="btn" onClick={() => setShowModal(false)} style={{ border: '1px solid var(--border)' }}>Cancel</button>
                                <button type="submit" className="btn btn-primary" style={{ padding: '0.75rem 2rem', borderRadius: '12px' }}>Save Invoice</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {filteredInvoices.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '5rem 3rem', background: 'var(--surface)' }}>
                    <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🧾</div>
                    <h3 style={{ fontWeight: 800, color: 'var(--text-main)' }}>No Matching Invoices</h3>
                    <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>Try adjusting your filters or search terms.</p>
                </div>
            ) : (
                <div className="card" style={{ overflow: 'hidden', padding: 0, border: '1px solid var(--border)' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead>
                            <tr style={{ background: 'var(--background)', borderBottom: '2px solid var(--border)' }}>
                                <th style={{ padding: '1.25rem 1.5rem', fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-secondary)', textTransform: 'uppercase' }}>Status</th>
                                <th style={{ padding: '1.25rem 1.5rem', fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-secondary)', textTransform: 'uppercase' }}>Invoice #</th>
                                <th style={{ padding: '1.25rem 1.5rem', fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-secondary)', textTransform: 'uppercase' }}>Reference</th>
                                <th style={{ padding: '1.25rem 1.5rem', fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-secondary)', textTransform: 'uppercase' }}>Due Date</th>
                                <th style={{ padding: '1.25rem 1.5rem', fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-secondary)', textTransform: 'uppercase', textAlign: 'right' }}>Amount</th>
                                <th style={{ padding: '1.25rem 1.5rem', fontSize: '0.75rem', fontWeight: 800, color: 'var(--text-secondary)', textTransform: 'uppercase', textAlign: 'center' }}>Attachment</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredInvoices.map((inv: Invoice, idx: number) => (
                                <tr
                                    key={inv.id}
                                    onClick={() => setSelectedInvoice(inv)}
                                    style={{
                                        borderBottom: '1px solid var(--border)',
                                        cursor: 'pointer',
                                        transition: 'all 0.2s',
                                        background: idx % 2 === 0 ? 'var(--surface)' : 'rgba(0,0,0,0.01)'
                                    }}
                                    onMouseEnter={(e) => e.currentTarget.style.background = 'rgba(4, 156, 99, 0.03)'}
                                    onMouseLeave={(e) => e.currentTarget.style.background = idx % 2 === 0 ? 'var(--surface)' : 'rgba(0,0,0,0.01)'}
                                >
                                    <td style={{ padding: '1.25rem 1.5rem' }}>
                                        <span style={{
                                            padding: '4px 12px',
                                            borderRadius: '8px',
                                            fontSize: '0.7rem',
                                            fontWeight: 800,
                                            background: inv.status === 'PAID' ? '#D1FAE5' : inv.status === 'APPROVED' ? '#DBEAFE' : inv.status === 'REJECTED' ? '#FEE2E2' : '#FEF3C7',
                                            color: inv.status === 'PAID' ? '#065F46' : inv.status === 'APPROVED' ? '#1E40AF' : inv.status === 'REJECTED' ? '#991B1B' : '#92400E'
                                        }}>
                                            {inv.status}
                                        </span>
                                    </td>
                                    <td style={{ padding: '1.25rem 1.5rem' }}>
                                        <div style={{ fontWeight: 800, color: 'var(--text-main)', fontSize: '0.95rem' }}>{inv.invoiceNumber}</div>
                                        <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>Created {new Date(inv.createdAt).toLocaleDateString()}</div>
                                    </td>
                                    <td style={{ padding: '1.25rem 1.5rem' }}>
                                        <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{inv.vendorName}</div>
                                        <div style={{ fontSize: '0.75rem', color: 'var(--accent)', fontWeight: 600 }}>#{inv.poNumber}</div>
                                    </td>
                                    <td style={{ padding: '1.25rem 1.5rem' }}>
                                        <div style={{ fontSize: '0.9rem', fontWeight: 500 }}>{new Date(inv.dueDate).toLocaleDateString()}</div>
                                        {new Date(inv.dueDate) < new Date() && inv.status === 'PENDING' && <div style={{ fontSize: '0.7rem', color: '#EF4444', fontWeight: 700 }}>OVERDUE</div>}
                                    </td>
                                    <td style={{ padding: '1.25rem 1.5rem', textAlign: 'right', fontWeight: 900, fontSize: '1rem' }}>
                                        {formatCurrency(inv.amount, inv.currency)}
                                    </td>
                                    <td style={{ padding: '1.25rem 1.5rem', textAlign: 'center' }}>
                                        {inv.fileName ? <span title={inv.fileName}>📎</span> : <span style={{ opacity: 0.2 }}>—</span>}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Detail / 3-Way Match Modal */}
            {selectedInvoice && (
                <InvoiceDetailModal
                    invoice={selectedInvoice}
                    po={pos.find(p => p.id === selectedInvoice.poId)}
                    onClose={() => setSelectedInvoice(null)}
                    onPay={handlePay}
                    onStatusUpdate={handleStatusUpdate}
                />
            )}
        </div>
    );
}
